/* ----- Conferencia rapida ----- */
SELECT 'Empresa' AS Tabela, COUNT(*) AS Linhas FROM dbo.Empresa
UNION ALL SELECT 'Usuario', COUNT(*) FROM dbo.Usuario
UNION ALL SELECT 'Categoria', COUNT(*) FROM dbo.Categoria
UNION ALL SELECT 'Produto', COUNT(*) FROM dbo.Produto
UNION ALL SELECT 'ModeloMoto', COUNT(*) FROM dbo.ModeloMoto
UNION ALL SELECT 'Veiculo', COUNT(*) FROM dbo.Veiculo
UNION ALL SELECT 'SecaoModelo', COUNT(*) FROM dbo.SecaoModelo
UNION ALL SELECT 'PecaSecao', COUNT(*) FROM dbo.PecaSecao
UNION ALL SELECT 'Pedido', COUNT(*) FROM dbo.Pedido
UNION ALL SELECT 'PedidoItem', COUNT(*) FROM dbo.PedidoItem
